// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {

	// 2.5.13:  08.10.20  | KT | SEQ | STRY0076607:  SEQ - Task Form – WAITING State – Flag passes from Parent Task to Subtask
	if(newValue == 'true'){
		if(g_scratchpad.calchaschildren <= 0)
			g_form.showFieldMsg('u_wait_for_subtasks_to_finish', getMessage('Tasker - Wait State Warning Message'), 'error', false);

		g_form.showFieldMsg('u_wait_for_subtasks_to_finish', getMessage('Tasker - Wait State Information Message'),'info');

		if (g_form.getDisplayValue('tasker_type') == 'Approval with signature' || (g_form.getDisplayValue('tasker_type') == 'Approval without signature') && 1) {

			if (g_scratchpad.numApprovalSubTasks >= 1){
				g_form.showFieldMsg('u_wait_for_subtasks_to_finish', getMessage('Tasker - Wait State - Information - Approval type with Approval Subtask'),'info');
			}
		}
	} else if (!isLoading && newValue == 'false'){
		g_form.showFieldMsg('u_wait_for_subtasks_to_finish', getMessage('Tasker - Wait State Information - Task is no longer dependent on the completion of its Subtasks'),'info');
	}

}
